import{_ as p,C as l,o as m,c as h,j as n,a as i,E as e,a3 as s}from"./chunks/framework.CVjg771q.js";const x=JSON.parse('{"title":"阴符经","description":"一部篇幅极短、语言峻利的道家经典。","frontmatter":{"title":"阴符经","description":"一部篇幅极短、语言峻利的道家经典。","category":"guide","aliases":["阴符经","黄帝阴符经","yinfu jing","阴符"],"source":["《黄帝阴符经》"]},"headers":[],"relativePath":"daoism/starter-texts/yinfu-jing.md","filePath":"daoism/starter-texts/yinfu-jing.md","lastUpdated":1779783531000}'),d={name:"daoism/starter-texts/yinfu-jing.md"};function g(u,a,y,b,c,f){const o=l("DaoReadingPrelude"),r=l("DaoOriginalReading"),t=l("DaoKeywordCards");return m(),h("div",null,[a[0]||(a[0]=n("h1",{id:"阴符经",tabindex:"-1"},[i("阴符经 "),n("a",{class:"header-anchor",href:"#阴符经","aria-label":'Permalink to "阴符经"'},"​")],-1)),e(o,{title:"先分上中下三篇，再顺着机的脉络读",summary:"《阴符经》篇幅不长，但语势峻厉、转折密集。更适合的进入方式，是先按上、中、下三篇分别去读：上篇看天道与杀机，中篇看三盗与时机，下篇看自然之道与阴阳变化。",points:[{label:"先读",text:"先顺着三篇各读一遍，不急着逐句解释。"},{label:"再辨",text:"留意“机”怎样在天、人、万物之间反复出现。"},{label:"后想",text:"最后回到自然之道、应机而动这条总线。"}],hint:"这篇适合分篇读，不必一口气把三篇压成一团；先让每一篇各自立住，再回头看它们如何互相照应。"}),a[1]||(a[1]=n("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),n("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),a[2]||(a[2]=n("h3",{id:"上篇",tabindex:"-1"},[i("上篇 "),n("a",{class:"header-anchor",href:"#上篇","aria-label":'Permalink to "上篇"'},"​")],-1)),e(r,{chapterMark:"上篇",colophon:"观天 · 杀机 · 修炼",tone:"ink",skin:"yinfu",paragraphs:["观天之道，执天之行，尽矣。","天有五贼，见之者昌。","五贼在心，施行于天。","宇宙在乎手，万化生乎身。","天性，人也；人心，机也。","立天之道，以定人也。","天发杀机，移星易宿；","地发杀机，龙蛇起陆；","人发杀机，天地反覆。","天人合发，万变定基。","性有巧拙，可以伏藏。","九窍之邪，在乎三要，可以动静。","火生于木，祸发必克；","奸生于国，时动必溃。","知之修炼，谓之圣人。"],"aria-label":"阴符经上篇原文"}),a[3]||(a[3]=n("h3",{id:"中篇",tabindex:"-1"},[i("中篇 "),n("a",{class:"header-anchor",href:"#中篇","aria-label":'Permalink to "中篇"'},"​")],-1)),e(r,{chapterMark:"中篇",colophon:"三盗 · 时机 · 神明",tone:"ink",skin:"yinfu",paragraphs:["天生天杀，道之理也。","天地，万物之盗；","万物，人之盗；","人，万物之盗。","三盗既宜，三才既安。","故曰：食其时，百骸理；","动其机，万化安。","人知其神之神，不知不神之所以神。","日月有数，大小有定；","圣功生焉，神明出焉。","其盗机也，天下莫能见，莫能知。","君子得之固躬，小人得之轻命。"],"aria-label":"阴符经中篇原文"}),a[4]||(a[4]=n("h3",{id:"下篇",tabindex:"-1"},[i("下篇 "),n("a",{class:"header-anchor",href:"#下篇","aria-label":'Permalink to "下篇"'},"​")],-1)),e(r,{chapterMark:"下篇",colophon:"自然 · 阴阳 · 制机",tone:"ink",skin:"yinfu",paragraphs:["瞽者善听，聋者善视。","绝利一源，用师十倍。","三返昼夜，用师万倍。","心生于物，死于物，机在目。","天之无恩而大恩生，","迅雷烈风，莫不蠢然。","至乐性余，至静性廉。","天之至私，用之至公。","禽之制在气。","生者死之根，死者生之根。","恩生于害，害生于恩。","愚人以天地文理圣，","我以时物文理哲。","人以愚虞圣，我以不愚虞圣；","人以奇期圣，我以不奇期圣。","故曰：沉水入火，自取灭亡。","自然之道静，故天地万物生。","天地之道浸，故阴阳胜。","阴阳相推，而变化顺矣。","是故圣人知自然之道不可违，","因而制之。","至静之道，律历所不能契。","爰有奇器，是生万象，","八卦甲子，神机鬼藏。","阴阳相胜之术，昭昭乎进乎象矣。"],"aria-label":"阴符经下篇原文"}),a[5]||(a[5]=n("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),n("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),a[6]||(a[6]=n("h3",{id:"上篇-1",tabindex:"-1"},[i("上篇 "),n("a",{class:"header-anchor",href:"#上篇-1","aria-label":'Permalink to "上篇"'},"​")],-1)),e(t,{items:[{term:"执天之行",pinyin:["zhí","tiān","zhī","xíng"],meaning:"把握天道的运行法则并依之而行。开篇「观天之道，执天之行」观与执并举：观是看清，执是循行，二者不可偏废。"},{term:"尽",pinyin:["jìn"],meaning:"穷尽、完备。「观天之道，执天之行，尽矣」——天道与人行合一，便是全部要义，无需更多繁复名相。"},{term:"贼",pinyin:["zéi"],meaning:"非盗贼之贼，而是天地间相互制衡、相互夺取的力量。「天有五贼」即五行相克相夺之理，见之者能顺势而为。"},{term:"施行",pinyin:["shī","xíng"],meaning:"推行、作用于外。「五贼在心，施行于天」——心中明了五贼之理，再将其推行到天地之间，由内而外。"},{term:"万化",pinyin:["wàn","huà"],meaning:"万事万物的变化。「宇宙在乎手，万化生乎身」——天地变化虽繁，皆可由人身而感知、由人心而推演。"},{term:"定基",pinyin:["dìng","jī"],meaning:"沉定的根基。「天人合发，万变定基」——变化再多，只要天人合机，最终仍能落到一个新的稳固根基上。"},{term:"伏藏",pinyin:["fú","cáng"],meaning:"收敛潜藏。「性有巧拙，可以伏藏」——人无论性分巧拙，都不必急于尽发，懂得收敛、留有余地才是工夫。"},{term:"九窍",pinyin:["jiǔ","qiào"],meaning:"人身九窍（眼耳鼻口等），是感官与外物相接的门户。窍开则心易被牵，守窍之要在于知动静。"},{term:"邪",pinyin:["xié"],meaning:"此处不单指邪恶，更指感官引动心念、使人偏离本然的扰动。「九窍之邪」即从窍而入的散乱与偏移。"},{term:"溃",pinyin:["kuì"],meaning:"崩坏、溃散。「奸生于国，时动必溃」——祸乱非凭空而来，总有生处；时机一到，积累的祸患必然爆发。"},{term:"修炼",pinyin:["xiū","liàn"],meaning:"修真炼己。「知之修炼，谓之圣人」——知机是看见，修炼是做到；只知不修不够，只修不知也不够。"}]}),a[7]||(a[7]=n("h3",{id:"中篇-1",tabindex:"-1"},[i("中篇 "),n("a",{class:"header-anchor",href:"#中篇-1","aria-label":'Permalink to "中篇"'},"​")],-1)),e(t,{items:[{term:"盗",pinyin:["dào"],meaning:"非偷窃之盗，而是天地万物之间相互资取、相互消耗的自然关系。「天地，万物之盗」点出这种互取互用的本质。"},{term:"三才",pinyin:["sān","cái"],meaning:"天、地、人。「三盗既宜，三才既安」——天地盗万物、万物盗人、人盗万物，三盗各得其宜则三才安定。"},{term:"百骸理",pinyin:["bǎi","hái","lǐ"],meaning:"身体百骸自然调顺。「食其时，百骸理」——饮食合于时节，身体的各个部分便自然理顺，强调顺时的重要。"},{term:"安",pinyin:["ān"],meaning:"安定、归位。「动其机，万化安」——不是消除变化，而是让变化在得其时机后归于安定。"},{term:"神",pinyin:["shén"],meaning:"「人知其神之神，不知不神之所以神」——世人只见神奇灵妙的一面为神，却不知那看似平常、不显神异的道，才是真正的神妙所在。"},{term:"固躬",pinyin:["gù","gōng"],meaning:"稳固自身。「君子得之固躬」——君子得到盗机之理，能用来稳固自身，不妄动、不轻发。"},{term:"轻命",pinyin:["qīng","mìng"],meaning:"轻忽性命。「小人得之轻命」——同样的盗机之理，小人得之则因贪求而轻忽自身性命，反受其害。"}]}),a[8]||(a[8]=n("h3",{id:"下篇-1",tabindex:"-1"},[i("下篇 "),n("a",{class:"header-anchor",href:"#下篇-1","aria-label":'Permalink to "下篇"'},"​")],-1)),e(t,{items:[{term:"瞽",pinyin:["gǔ"],meaning:"目盲。「瞽者善听」——盲人失去视觉后听觉反而敏锐，喻专注一源则其用倍增，不因缺失而废。"},{term:"绝利一源",pinyin:["jué","lì","yī","yuán"],meaning:"断绝其他利益，专注一个源头。「绝利一源，用师十倍」——精力不分散，聚焦一处，效力可抵十倍。"},{term:"大恩",pinyin:["dà","ēn"],meaning:"「天之无恩而大恩生」——天道看似无情无恩于万物，却以不偏私的方式成就万物，这便是最大的恩。"},{term:"蠢然",pinyin:["chǔn","rán"],meaning:"生动跃动之貌。「迅雷烈风，莫不蠢然」——天地变化虽然猛烈，却自有生机，不是死寂的。"},{term:"余",pinyin:["yú"],meaning:"宽裕、有余。「至乐性余」——真正安乐的人心性宽裕不迫，不因得失而紧绷。"},{term:"廉",pinyin:["lián"],meaning:"简约、不贪。「至静性廉」——真正静定的人心性简约，不被多余的欲望牵走。"},{term:"禽之制",pinyin:["qín","zhī","zhì"],meaning:"擒获、制伏的方法。「禽之制在气」——要制伏外物，关键在把握其气机，而不是硬碰硬的对抗。"},{term:"圣",pinyin:["shèng"],meaning:"「愚人以天地文理圣，我以时物文理哲」——圣在此为通达、不拘泥，不是死守固定文理，而是随时物之变而通达。"},{term:"哲",pinyin:["zhé"],meaning:"明达事理。与「圣」呼应：愚者以固定文理为圣，我则以随时应变、通达事理为明哲。"},{term:"愚",pinyin:["yú"],meaning:"「愚人以天地文理圣」——愚在此是不明变通、拘泥于固定文理，而非单纯的愚蠢。"},{term:"虞圣",pinyin:["yú","shèng"],meaning:"「人以愚虞圣」——以愚昧之心去揣度圣人之境，必然偏差。虞为揣度、测度。"},{term:"奇",pinyin:["qí"],meaning:"「人以奇期圣」——以奇异、非常的标准去期待圣人，反而看不清圣人之道的平常真实。"},{term:"期圣",pinyin:["qī","shèng"],meaning:"期待、衡量圣人之境。「人以奇期圣，我以不奇期圣」——不以奇异标准衡量圣人，才能贴近真实。"},{term:"契",pinyin:["qì"],meaning:"契合、穷尽。「至静之道，律历所不能契」——最深的静定之道，非律历、度数所能完全测度与穷尽。"},{term:"爰",pinyin:["yuán"],meaning:"于是、乃。「爰有奇器，是生万象」——于是有此奇妙的法则（奇器），生出天地万象。"},{term:"奇器",pinyin:["qí","qì"],meaning:"奇妙的法则或器物。「爰有奇器，是生万象，八卦甲子，神机鬼藏」——指八卦、甲子等推演万象的工具与法则。"},{term:"昭昭乎",pinyin:["zhāo","zhāo","hū"],meaning:"明亮清晰的样子。「阴阳相胜之术，昭昭乎进乎象矣」——阴阳制衡推变之法，明白可见地显现于卦象物象之中。"},{term:"进乎象",pinyin:["jìn","hū","xiàng"],meaning:"进入、显现于象（卦象、物象）之中。全经最后一句：至微的道理，终究要落到可见可用的象上，而非悬空。"}]}),a[9]||(a[9]=s("",46))])}const q=p(d,[["render",g]]);export{x as __pageData,q as default};
